INSERT INTO public.photos VALUES (22663, 'Porches Mercado 1979', 'Porches junto al Mercado Central, en el tramo entre la calle de San Blas y la calle de Las Armas (al fondo). Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65608700, -0.88328400, '0101000020E6100000E28FA2CEDC43ECBF562AA8A8FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22752472359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22752472359.webp', 'https://www.flickr.com/photos/zaragozaantigua/22752472359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22676, 'Calle de San Pablo 1978', 'Imagen capturada durante las obras de restauraci├│n de la iglesia de San Pablo Ap├│stol acometidas a finales de los a├▒os setenta del siglo XX, cuando de la fachada principal fue erradicada la intervenci├│n que a finales del siglo XVIII hab├¡a a├▒adido en piedra un nuevo muro y elementos decorativos tardo-neocl├ísicos (pilastras lisas, cornisa superior y hornacinas con jarrones). Esta restauraci├│n promovida por el Ministerio de la Vivienda pretend├¡a conferir al conjunto aires (neo) medievales en formas (neo) mud├®jares, al gusto de la ├®poca. Fuente visual: AMZ.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST├ôRICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24870123688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24870123688.webp', 'https://www.flickr.com/photos/zaragozaantigua/24870123688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22678, 'General Franco 1978', 'Imagen de la esquinera fachada, recayente a las calles general Franco, y Ram├│n y Cajal, de la antigua manzana delimitada por las calles Boggiero, Miguel de Ara (izquierda), general Franco, y Ram├│n y Cajal (derecha). Todo este frontal habitacional, con bajos comerciales, fue derribado poco despu├®s. A la izquierda, se intuye ya el derribo consumado del antiguo n┬║ 23 de la calle Miguel de Ara. Estas viviendas, de tres alturas, m├ís los bajos, son testimonio de una tipolog├¡a edilicia que ha sido masacrada sin demasiados miramientos en la ciudad, de forma especialmente destacable en la d├®cada de los a├▒os 70 del pasado siglo XX. Tras los importantes retranqueos realizados para ensanchar las calles de Boggiero, Miguel de Ara, y algo menos la de Ram├│n y Cajal, la mayor parte de esta manzana perdur├│ como un despejado y c├®ntrico solar en el que apenas superviven un par de antiguas viviendas. En 2025 el solar fue edificado. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza-DARA.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST├ôRICO', 41.65477500, -0.88596400, '0101000020E6100000F4DDAD2CD159ECBF849ECDAACFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26177207453.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26177207453.webp', 'https://www.flickr.com/photos/zaragozaantigua/26177207453/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22702, 'Calle San Pablo 1978', 'Imagen de la calle de San Pablo, capturada desde la plaza del mismo nombre. A la izquierda, inmediata, queda la iglesia parroquial, a la derecha, el arranque de la calle Miguel de Ara, y al fondo, el principio de la calle de San Pablo desde el despejado panorama que hab├¡a dejado el reciente derribo de la manzana de la calle de las Escuelas P├¡as,convertida en parte de la moderna avenida de C├®sar Augusto. Fuente visual: amable aportaci├│n personal de Pablo Vald├®s.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST├ôRICO', 41.65582500, -0.88573900, '0101000020E6100000F855B950F957ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27471392250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27471392250.webp', 'https://www.flickr.com/photos/zaragozaantigua/27471392250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22780, 'Calle de San Blas 1979', 'Imagen capturada en la calle de San Blas del barrio de San Pablo, con una vista parcial del tramo comprendido entre la calle de Aguadores (hacia la derecha) y la plaza de Santo Domingo (hacia la izquierda) centrada en la radical contraposici├│n entre el moderno bloque de los n├║meros 100-102 (derecha), y las antiguas viviendas de los n├║meros 104 al 124 (izquierda). Mediante importantes y quir├║rgicos cambios de alineaci├│n, el Plan de Reforma Interior aplicado supuso el arrasamiento y destrucci├│n de importantes sectores del tradicional tejido urbano con la excusa del "saneamiento" y ensanchamiento para habilitar aparcamiento en superficie al autom├│vil y mayor superficie para el tr├ínsito rodado. Eran los tiempos en que estas intervenciones incluyeron, adem├ís, los espeluznantes bloques habitacionales de la calle de Santa Luc├¡a angular con la plaza de Santo Domingo, la destrucci├│n de buena parte del convento de las Fecetas, et alia. Tiempo despu├®s de la realizaci├│n de esta fotograf├¡a, las parcelas de la izquierda ser├¡an derribadas. Fuente visual: Andal├ín, peri├│dico semanal aragon├®s, 1979.', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65665100, -0.88774500, '0101000020E61000002A00C6336868ECBF5EF1D4230DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37719939034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37719939034.webp', 'https://www.flickr.com/photos/zaragozaantigua/37719939034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22832, 'Rastro del Mercado 1985', 'Foto: Arturo Burgos. Mayo de 1985. El rastro de Zaragoza uno de sus domingos de esplendor, en la avenida de C├®sar Augusto, junto al Mercado Central. Ese mismo a├▒o ser├í trasladado a dos ubicaciones, seg├║n la mercader├¡a: los cachivaches, junto a la plaza de toros; la ropa y similares, junto al estadio de f├║tbol. Fuente: dezaragozaalzierzo.blogspot.com', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST├ôRICO', 41.65532600, -0.88373600, '0101000020E6100000098849B89047ECBFF81BEDB8E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14712649239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14712649239.webp', 'https://www.flickr.com/photos/zaragozaantigua/14712649239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22845, 'Av. C├®sar Augusto a├▒os 80', 'A├▒os 80. En C├®sar Augusto, entre los chipirones, a la izquierda, del "Chipir├│n", y los millones de la Agencia urbana 6 "Lanuza", a la derecha, all├¡ estaba "Calzados-Cordeler├¡a Sebasti├ín Sieso", con alpargatas, botas de calzar, persianas, botas de vino, cestas, bolsos, sillas... Llevaba desde 1931 por el barrio, cuando la calle se llamaba de Antonio P├®rez.', 1980, 1980, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15132487785.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15132487785.webp', 'https://www.flickr.com/photos/zaragozaantigua/15132487785/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22854, 'Calle San Pablo a├▒os 80', 'Calle de San pablo en los a├▒os 80, con su antigua pavimentaci├│n. A la derecha, calle de Broqueleros. A la izquierda, Echeand├¡a. Fuente: www.facebook.com/photo.php?fbid=1578893569005540&set=...', 1980, 1980, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65554800, -0.88449100, '0101000020E61000001B67D311C04DECBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15479806726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15479806726.webp', 'https://www.flickr.com/photos/zaragozaantigua/15479806726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22870, 'Av. C├®sar Augusto c.1984', 'Tr├ífico rodado proveniente del paseo de Echegaray y Caballero, a su paso por el cruce de la calle de San Blas (a la izquierda) con la avenida de C├®sar Augusto y la plaza de Lanuza (a la derecha, fuera de plano). Tras las viandantes, el Mercado Central. Fuente: Foto aportada por Javier Pe├▒a Gonzalvo a Fotos Antiguas de Zaragoza: www.facebook.com/photo.php?fbid=998859546796557&set=o...', 1984, 1984, 1984, 'Anos 80', 'CASCO HIST├ôRICO', 41.65591000, -0.88340200, '0101000020E61000005E126745D444ECBF478FDFDBF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15788242195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15788242195.webp', 'https://www.flickr.com/photos/zaragozaantigua/15788242195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22902, 'Av. C├®sar Augusto 1989', 'Porches junto al Mercado Central, en la avenida C├®sar Augusto, esquina con la calle de San Blas (izquierda), el 7 de octubre de 1989. Fuente: "Memoria de las calles de Zaragoza", Juli├ín Ruiz Mar├¡n, Librer├¡a General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21351408703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21351408703.webp', 'https://www.flickr.com/photos/zaragozaantigua/21351408703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22934, 'El rastro 1985', 'Ilustraci├│n de Alberto Calvo de 1988, representando el rastro de Zaragoza, situado en la avenida de C├®sar Augusto, junto al Mercado Central. En el momento de ser realizado el dibujo, este mercadillo se hab├¡a trasladado a sus dos ubicaciones en la Plaza de Toros y La Romareda. Fuente: Heraldo de Arag├│n.', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST├ôRICO', 41.65565200, -0.88359600, '0101000020E61000009A0B5C1E6B46ECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31887327236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31887327236.webp', 'https://www.flickr.com/photos/zaragozaantigua/31887327236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22175, 'P.┬║ de Isabel la Cat├│lica 1955', 'Imagen del tranquilo paseo de Isabel la Cat├│lica, centrada en la gran estructura del Colegio-Residencia de Nuestra Se├▒ora del Pilar para Hu├®rfanos e Hijos del Magisterio. A su izquierda, la monumental Residencia Sanitaria Jos├® Antonio. En primer plano, el camino de hierro habilitado para servicio de la tranviaria l├¡nea 15, o de Casablanca. Fuente visual: Foto Estudio Coyne, AHPZ.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63401800, -0.90284100, '0101000020E61000002C9D0FCF12E4ECBFA489778027D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31551895531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31551895531.webp', 'https://www.flickr.com/photos/zaragozaantigua/31551895531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22960, 'Calle de San Blas c.1981', 'Imagen capturada en la plaza de San Pablo y centrada en el inmediato tramo de la calle de San Blas, con el aspecto que entonces esta presentaba, alternando antiguos inmuebles y solares de los ya derribados, de su tramo comprendido entre los n├║meros 62 (a la derecha)-74 (hacia el fondo). En primer t├®rmino y a la izquierda, el esquinero inmueble del n┬║ 4 de la plaza de San Pablo. Todos los edificios que aqu├¡ aparecen luego fueron integralmente intervenidos, y sobre los solares se construyeron nuevas estructuras habitacionales, que junto con una preceptiva urbanizaci├│n impulsada por el Ayuntamiento le dio un nuevo aspecto a esta tradicional zona del barrio de San Pablo.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.65645100, -0.88639300, '0101000020E610000010E84CDA545DECBF97361C9606D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52124550314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52124550314.webp', 'https://www.flickr.com/photos/zaragozaantigua/52124550314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22963, 'Avda. de C├®sar Augusto 1985', 'Imagen capturada en la avenida de C├®sar Augusto a espaldas del Mercado Lanuza y centrada en el solar esquinero con la calle de San Blas donde estuviera el inmueble que tradicionalmente acogi├│ el comercio textil "El Peque├▒o Catal├ín", adem├ís de un par de casas en el arranque de la calle de San Blas, una de las cuales tras ser derribada dej├│ su impronta en la medianera del edificio del n┬║ 7-9, a la derecha de la imagen. Del edificio del comercio textil perduraba aqu├¡ apenas el arranque del grueso pilar de uno de sus soportales, sobre el que aparece sentado un ciudadano en el centro de la foto. A finales del siglo XX y principios del XXI esta manzana hasta la calle de San Pablo adquirir├¡a su actual aspecto, mediante la integral construcci├│n de inmuebles de nueva planta y conservando restaurada la fachada del abalconado edificio del n┬║ 37 (actual n┬║ 73), a la izquierda. En primer t├®rmino, convivencia de firmes: el antiguo adoquinado de la calle de San Blas, y el moderno asfaltado de la avenida de C├®sar Augusto.', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST├ôRICO', 41.65549500, -0.88403400, '0101000020E610000082AAD1AB014AECBF84D89942E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53259501638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53259501638.webp', 'https://www.flickr.com/photos/zaragozaantigua/53259501638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22975, 'Gabino Diego y Javier Gurruchaga 1994', 'Foto GEA. Noviembre de 1994. El escritor Luis Alegre presenta su primer libro, "Besos robados" en la Sala Oasis, a├║n Cabaret, poco antes del desmantelamiento de las butacas. Javier Gurruchaga, en la ciudad porque representaba "Golfus de Roma" en el teatro Principal, realiz├│ un energ├®tico concierto para el evento. En la foto, acompa├▒ado de Gabino Diego, compa├▒ero del cantante en la citada comedia musical.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST├ôRICO', 41.65507100, -0.88560200, '0101000020E6100000CCB56801DA56ECBF6DC7D45DD9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15105613266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15105613266.webp', 'https://www.flickr.com/photos/zaragozaantigua/15105613266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23039, 'Av. de C├®sar Augusto 1991', 'Imagen capturada desde la altura del inmueble del n┬║ 1 de la calle del Conde de Aranda y centrada en el remodelado tramo de la avenida de C├®sar Augusto donde destacan la entrada y salida del nuevo aparcamiento subterr├íneo con capacidad para 349 veh├¡culos. En la funcionalidad moderna del resultado destaca la recuperaci├│n del empedrado y las farolas "de corte antiguo". El importe total de esta intervenci├│n, unos 402 millones de pesetas, fue cubierto por la empresa Estacionamientos El Pilar, S.A. (EPSA), concesionaria de la explotaci├│n comercial del aparcamiento, cuyas instalaciones pasar├ín a propiedad municipal en el a├▒o 2041.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65465300, -0.88429200, '0101000020E61000006DA983BC1E4CECBF399D64ABCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50378130418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50378130418.webp', 'https://www.flickr.com/photos/zaragozaantigua/50378130418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23049, 'Calle de las Armas 1994', 'Aspecto del primer tramo de la calle de las Armas con el tel├│n de fondo del Mercado Central Lanuza y la avenida de C├®sar Augusto. En primer t├®rmino y a la izquierda, vecinos de la zona sentados junto al decimon├│nico inmueble del n┬║ 22-26, proyectado por Ricardo Magdalena, donde se ubicaran las antiguas "escuelas de la Golondrina", por el nombre de la calle luego redenominada de Mos├®n Pedro Dosset, y que actualmente acoge al Centro P├║blico de Educaci├│n de Personas Adultas (CPEPA) G├│mez Lafuente. Hacia el fondo, flanquean el contenedor de basura los solares de los antiguos n┬║ 8, 10 y 12 a la izquierda, y a la derecha de los derribados n┬║ 5, 7 y 11, algunos luego reedificados.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST├ôRICO', 41.65647300, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF7FDAA84E07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50440860042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50440860042.webp', 'https://www.flickr.com/photos/zaragozaantigua/50440860042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23073, 'Barrio de San Pablo 2004', 'Reciente vista en altura de la antigua "Poblaci├│n del Rey", vertebrada sobre los ejes perpendiculares que part├¡an de la plaza del Mercado (Las Armas, San Blas -a la izquierda de la torre-, San Pablo, Boggiero), con la referencia central de la g├│tica iglesia de San Pablo.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15257002696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15257002696.webp', 'https://www.flickr.com/photos/zaragozaantigua/15257002696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23077, 'Vista Oeste 2009', 'Foto Javier Pe├▒a, diciembre 2009. Vista desde la torre de la Seo del oeste de Zaragoza. Preside la imagen la torre de San Pablo. Fuente: www.facebook.com/photo.php?fbid=1012283062120872&set=...', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15899294026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15899294026.webp', 'https://www.flickr.com/photos/zaragozaantigua/15899294026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23093, 'SEPU Torre Nueva ca. 2000', 'Vista del edificio de los almacenes SEPU (Sociedad Espa├▒ola de Precios ├Ünicos) en la calle Torre Nueva de Zaragoza, esquina con la de Ant├│n Trillo, seg├║n proyecto de Miguel ├üngel Navarro de 1935. Se levanta en el solar de la antigua casa palacio de los condes de Bureta. Durante siete d├®cadas alberg├│ esos grandes almacenes, desaparecidos en 2002. Hoy est├í ocupado por viviendas y en sus bajos hay un supermercado. En el patio interior se conservan las escaleras mec├ínicas de madera, las primeras que se instalaron en Zaragoza. Fuente: AMZ.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21243415066.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21243415066.webp', 'https://www.flickr.com/photos/zaragozaantigua/21243415066/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23760, 'Pasarela del Bicentenario 2008', 'La pasarela del Bicentenario cruza el r├¡o Ebro entre La Cartuja Baja y La Alfranca, en el t├®rmino de Pastriz. Forma parte del Camino Natural de los Sotos y Galachos del Ebro, que conecta el final del paseo de Echegaray y Caballero con La Alfranca, sede del Centro Internacional del Agua y el Medio Ambiente. Fue dise├▒ada por Luis Javier Sanz. En la foto, ├║ltima fase de su construcci├│n, con las barandillas laterales sin colocar, el 17 de marzo de 2008. Ser├í inaugurada ese mismo a├▒o, el 6 de junio, junto con el Camino Natural de la Alfranca. Fuente: www.panoramio.com/photo/8625587', 2008, 2008, 2008, 'Siglo XXI', NULL, 41.61495600, -0.81578100, '0101000020E6100000755776C1E01AEABF4F3DD2E0B6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21556325342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21556325342.webp', 'https://www.flickr.com/photos/zaragozaantigua/21556325342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23102, 'Calle Torrenueva 2009', 'Imagen del nuevo edificio habilitado en la referencial esquina entre las calles de Torrenueva y Ant├│n Trillo. Aqu├¡ estuvo la solera de la antigua casa palacio de los condes de Bureta, derribada para construir, seg├║n proyecto de Miguel ├üngel Navarro en 1935, el edificio que alberg├│ por siete d├®cadas los irrepetibles almacenes SEPU (Sociedad Espa├▒ola de Precios ├Ünicos). En 2002 se produjo su cierre comercial, quedando en barbecho hasta la intervenci├│n que, proyectada en 2004, y respetando la fachada (catalogada de Inter├®s Ambiental), lo ha reconvertido en viviendas particulares y bajos comerciales. Sigue siendo uno de los abrumadores dominios de la nostalgia urbana, en su versi├│n m├ís desatada. Fuente: Joaqu├¡n Sicilia y Asociados, arquitectura.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194860103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194860103.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194860103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23460, 'Casa de la Condesa de Bureta 1935', 'Puerta de la casa de la Condesa de Bureta (Mar├¡a de la Consolaci├│n Domitila Azlor y Villavicencio (1773-1814), considerada hero├¡na de los asedios de Zaragoza (1808-1809) en la calle de Torre Nueva. Sobre el solar se construy├│ al poco tiempo el edificio de los almacenes SEPU (Sociedad Espa├▒ola de Precio ├Ünico). La imagen ilustra la noticia del inminente derribo de la casa. Fuente visual: foto Palacio, en Revista Blanco y Negro.', 1935, 1935, 1935, 'Anos 30', 'CASCO HIST├ôRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20548270379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20548270379.webp', 'https://www.flickr.com/photos/zaragozaantigua/20548270379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23924, '&quot;Parque de Artiller├¡a&quot; 1967', 'Archivo Municipal. Gerardo Sancho Ramo. 1967. La instalaci├│n militar del Ej├®rcito de Tierra denominada "Parque de Artiller├¡a" ocupaba 16440 m2 entre las calles de Agustina de Arag├│n y de Ram├│n Pignatelli, muy cerca de la plaza del Portillo, y del cuartel de Sangenis (o Pontoneros, de otros 15.681 m2 de extensi├│n). Con la denominada "Operaci├│n Cuarteles" (finales a├▒os setenta), y a cambio de unos dineros, este cuartel pas├│ a propiedad municipal. As├¡, se pudo prolongar la calle de Mayoral, y se construy├│ el Instituto de Educaci├│n Secundaria "Ram├│n y Cajal". En la imagen, turbamulta de ca├▒ones en desuso del "Parque". A la izquierda, tras los muros, la calle de Agustina de Arag├│n.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65492400, -0.89040200, '0101000020E61000003160C9552C7EECBFC9AEB48CD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15467645709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15467645709.webp', 'https://www.flickr.com/photos/zaragozaantigua/15467645709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23939, 'Calle San Mart├¡n c.1970', 'Pintura de Claudio G├│mez Villanueva publicada en 2014 en la revista de la Asociaci├│n Empresarial de Fontaner├¡a de Zaragoza. Recrea trabajos de fontaner├¡a en la calle de San Mart├¡n, esquina con la del General Franco (derecha). Al fondo se adivina la c├║pula de la iglesia de Santiago. Protagonizando la foto, la entrada del cine Victoria (1943-1985), con un reestreno de "Gilda" (Charles Vidor, 1946). Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65466800, -0.88632000, '0101000020E6100000944DB9C2BB5CECBF6EDE3829CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27584461584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27584461584.webp', 'https://www.flickr.com/photos/zaragozaantigua/27584461584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23952, 'San Ant├│n en San Pablo c.1969', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junto a la entrada a la Iglesia de San Pablo, el 17 de enero es el d├¡a de bendici├│n de animales irracionales, por obra y gracia del eremita San Ant├│n (251-356).', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65593600, -0.88619600, '0101000020E61000009012BBB6B75BECBF7022FAB5F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14740482207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14740482207.webp', 'https://www.flickr.com/photos/zaragozaantigua/14740482207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23986, 'Chicho S├ínchez Ferlosio 1986', 'Foto Roger Hernando. Jos├® Antonio Julio On├®simo S├ínchez Ferlosio devino en Chicho S├ínchez Ferlosio, se hizo trovador pensante, y se encontr├│ en la otra acera del R├®gimen. En el reino de los bardos, se relacion├│ con poetas polifac├®ticos, juglares con agujeros en los bolsillos, musas carnales, y gentes varias del poblado universo on├¡rico de las d├®cadas de los 70 y 80 del pasado siglo. Falleci├│ en 2003, y dej├│ una huella sonora perdurable. En la imagen, Chicho S├ínchez Ferlosio (a la derecha) sentado con Luis Felipe Alegre (otro que tal baila), en el Oasis. Fuente visual: elsilbovulnerado.blogspot.com.es/p/historial-grupo.html', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65522400, -0.88572900, '0101000020E610000014CD0358E457ECBFF3C64961DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15515040047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15515040047.webp', 'https://www.flickr.com/photos/zaragozaantigua/15515040047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24009, 'Juan de Lanuza 1591', 'La ejecuci├│n de Juan de Lanuza, boceto en acuarela sobre papel de Mariano Barbas├ín, Roma, 1891. Museo de Zaragoza. Representaci├│n de la decapitaci├│n de Juan V de Lanuza el Mozo, Justicia de Arag├│n, en la plaza del Mercado de Zaragoza, el 20 de diciembre de 1591. Al fondo, imagen ideal de la ciudad. Fuente: arte-paisaje.blogspot.com', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23985846539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23985846539.webp', 'https://www.flickr.com/photos/zaragozaantigua/23985846539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24024, 'Mercado Central 1917', 'Acceso sur del Mercado Central, custodiado por soldados de caballer├¡a, tras decretarse el estado de guerra en Espa├▒a a ra├¡z de la huelga general convocada por UGT y PSOE, en agosto de 1917. Al fondo, manzana de viviendas en la esquina de la plaza de Lanuza con la calle de la Torre Nueva (fuera de plano). Fuente: Archivo ABC.', 1917, 1917, 1917, 'Anos 10', 'CASCO HIST├ôRICO', 41.65564600, -0.88339100, '0101000020E61000006495D233BD44ECBF69E04735ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24746090791.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24746090791.webp', 'https://www.flickr.com/photos/zaragozaantigua/24746090791/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24064, 'Calle del General Franco c.1965', 'Puesto de venta de pipas, regaliz de palo, tortitas, etc., frente a la puerta del cine Monumental, en la calle del General Franco 32. Fuente: www.facebook.com/photo.php?fbid=1229130927118523&set=...', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65501100, -0.88734100, '0101000020E610000047CCECF31865ECBF98C28366D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33105800591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33105800591.webp', 'https://www.flickr.com/photos/zaragozaantigua/33105800591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24393, 'Avenida C├®sar Augusto 2011', 'Foto: Oliver Duch. On├¡rica y pict├│rica instant├ínea, tomada el 15 de noviembre de 2011, durante las obras de ampliaci├│n de la l├¡nea 1 del tranv├¡a. La avenida de C├®sar Augusto result├│ parcialmente anegada por la lluvia. Al fondo y reflejada en el agua, iglesia de Santo Tom├ís de Aquino o de los Escolapios. Fuente: Heraldo de Arag├│n.', 2011, 2011, 2011, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65539500, -0.88385200, '0101000020E6100000572250FD8348ECBF207BBDFBE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26052396338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26052396338.webp', 'https://www.flickr.com/photos/zaragozaantigua/26052396338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24439, 'Plaza de Lanuza 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/mayo 1965. Ambulante botijero mostrando mercanc├¡a a potencial clienta en la confluencia de Cerd├ín-Escuelas P├¡as-Plaza Lanuza, en la actualidad Avenida de C├®sar Augusto. A la derecha, esquina del Mercado Central, a la izquierda, la calle San Blas.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65566300, -0.88346600, '0101000020E61000000D18247D5A45ECBF3F19E3C3ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871349063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871349063.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871349063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24441, 'Pl. del Mercado 1869', '"Saragossa, the Market". Al fondo, las calles Cerd├ín y Escuelas P├¡as. Al fondo de la calle Cerd├ín, la c├║pula de la Iglesia de Santiago el Mayor. Fuente visual: Robert Peters Napper-Francis Frith & Co., en Victoria and Albert Museum, London, 1860-1870.', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14909212321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14909212321.webp', 'https://www.flickr.com/photos/zaragozaantigua/14909212321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24445, 'Mercado Central 1962', 'John "Ganso" Kovatch, militar del ej├®rcito de los EE.UU de Norteam├®rica destinado en la Base A├®rea de Zaragoza, haciendo turismo en la ciudad. En la imagen, detalle de entrada al Mercado Central, en la esquina con Torre Nueva.', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST├ôRICO', 41.65553500, -0.88331500, '0101000020E6100000A31EA2D11D44ECBF12312592E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15108587879.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15108587879.webp', 'https://www.flickr.com/photos/zaragozaantigua/15108587879/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24446, 'Mercado Central 1970', 'El pavo es azteca, omn├¡voro, proteico, y escandaloso. Encaja bien en esta ciudad. En la imagen, un peque├▒o reba├▒o de pavos es paseado para publicitar su venta por un orondo pavero, en el lado de los pares de la plaza de Lanuza. A la derecha y al fondo, esquina sur del Mercado Central con la calle de la Torre Nueva. Detr├ís de la pavada, un grupo de personas contempla esta tradicional escena invernal, asociada a la importada celebraci├│n azteca del solsticio de invierno, que pronto pasar├¡a de pintoresca a desaparecida en nuestros pagos.', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65562300, -0.88306900, '0101000020E6100000C99063EB1942ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15117496621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15117496621.webp', 'https://www.flickr.com/photos/zaragozaantigua/15117496621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24545, 'Nuevo Mercado 1895', '"Proyecto del Nuevo Mercado. Fachada frente a la calle de Cerd├ín; planta". F├®lix Navarro P├®rez, arquitecto, 1895. Tinta y acuarela sobre tela, 125 x 138 cm. Excelente ilustraci├│n del alzado sur del Nuevo Mercado de Zaragoza, que ser├í inaugurado en 1903 y luego denominado Mercado Central o de Lanuza.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65567300, -0.88336100, '0101000020E6100000B9FAB1497E44ECBF63EFC517EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54323517061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54323517061.webp', 'https://www.flickr.com/photos/zaragozaantigua/54323517061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24906, 'Necr├│polis paleocristiana siglo V', 'Necr├│polis paleocristiana bajo la calzada de la actual calle de Mos├®n Pedro Dosset, junto a la de Las Armas. ├ëpoca romana (s. V). Durante las obras de pavimentaci├│n y renovaci├│n de servicios de la zona en 2002, se encontr├│ en la antigua calle de la Golondrina un conjunto de inhumaciones en fosa, con cubierta de tejas planas y ata├║d de madera. Alguna presenta revestimiento de mosaico, hallazgo ├║nico en la historia de la ciudad. Estos restos se encontraron cerca de la necr├│polis occidental de Caesaraugusta (calle Predicadores 20-30, siglos III al XIII), si bien no forman parte de ese conjunto. Fuente: Revista Saldvie. Universidad de Zaragoza, 2002.', 450, 400, 499, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65660800, -0.88408900, '0101000020E6100000651BB803754AECBF5F251FBB0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18552193299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18552193299.webp', 'https://www.flickr.com/photos/zaragozaantigua/18552193299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25097, 'Muerte de Lanuza 1591', 'ÔÇ£Represi├│n de las tropas castellanas: muerte de don Juan de Lanuza (1564-1591) por defender a Antonio P├®rezÔÇØ. Grabado del siglo XIX coloreado posteriormente. El Justicia de Arag├│n permanece a la derecha, mientras preparan su decapitaci├│n en la plaza del Mercado. Al fondo, anacr├│nicas c├║pulas de San Ildefonso (centro) y Santo Tom├ís de Villanueva (izquierda). Fuente visual: www.superstock.com', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40205982815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40205982815.webp', 'https://www.flickr.com/photos/zaragozaantigua/40205982815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25134, 'San Pablo 1891', 'Dibujo de la plaza, iglesia y torre de San Pablo, en 1891.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18945535232.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18945535232.webp', 'https://www.flickr.com/photos/zaragozaantigua/18945535232/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25180, 'Iglesia de San Pablo 1943', 'Fotograf├¡a en blanco y negro del colorista lienzo "Vista urbana con iglesia y gente", firmado en 1943 por el paisajista barcelon├®s Ram├│n L├│pez Mu├▒oz. Posiblemente la imagen se ha capturado durante la exposici├│n de esta obra en la filial zaragozana de la Sala Gaspar de Barcelona, que desde 1942 estaba abierta en los bajos del inmueble del antiguo n┬║ 3 de la calle de la Yedra, esquinero con la plaza de la Le├▒a. Este espacio expositivo estuvo activo hasta su cierre en 1950. La pintura ilustra una vista desde cierta altura de la dieciochesca fachada de la iglesia parroquial de San Pablo Ap├│stol, recayente a la hom├│nima calle, posiblemente durante la salida de un oficio dominical. Al fondo y a la izquierda, la plaza de San Pablo.', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST├ôRICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48594159637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48594159637.webp', 'https://www.flickr.com/photos/zaragozaantigua/48594159637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25191, 'Plano del mercado y pellerich ca. 1460', 'La Plaza del Mercado era el m├ís importante espacio social de actos y celebraciones mercantiles y festivas de la ciudad, y tambi├®n el escenario de la impartici├│n de justicia, bien por los tribunales civiles, bien por el eclesi├ístico de la Inquisici├│n. Ese lugar concreto se denominaba "plaza de la Justicia", donde estaba instalada la "Picota", o "Pellerich" (denominaci├│n que aparece en las "Ordinaciones" reales otorgadas a la ciudad de Zaragoza, que desde el s.XIII regulaban la organizaci├│n municipal de la ciudad, incluyendo la Justicia). En este cadalso se ejecutaron p├║blicamente las condenas a muerte, mediante la horca, o la decapitaci├│n, como fue el caso del Justicia Juan de Lanuza a finales del s.XVI. Esto se hac├¡a al objeto de servir de ejemplo al p├║blico sobre los efectos de transgredir las normas sociales. El plano representa el lugar donde estaba localizado el cadalso, o "pellerich", en el espacio de la plaza del Mercado donde conflu├¡a el Trenque de la calle Nueva (calle Torrenueva), la calle de San Blas, la de San Pablo, la de la Cedacer├¡a (luego Escuelas P├¡as), y la de la Albarder├¡a (luego Cerd├ín). Fuente: M┬¬ Isabel Falc├│n P├®rez, "Zaragoza en el siglo XV: morfolog├¡a urbana, huertas y t├®rmino municipal", IFC, 2011.', 1460, 1460, 1460, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65577500, -0.88325100, '0101000020E6100000F418E5999743ECBF6744696FF0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15791168710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15791168710.webp', 'https://www.flickr.com/photos/zaragozaantigua/15791168710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25379, 'Calle de las Escuelas P├¡as c.1976', 'En 1977 se derrib├│ la manzana que formaban las calles Cerd├ín y Escuelas P├¡as, en el tramo de la actual avenida de C├®sar Augusto que llega del Coso al Mercado Central. Al fondo, la iglesia de las Escuelas P├¡as.', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST├ôRICO', 41.65487100, -0.88427000, '0101000020E610000079AF5A99F04BECBFA60C1CD0D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14715464178.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14715464178.webp', 'https://www.flickr.com/photos/zaragozaantigua/14715464178/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25380, 'Calle Cerd├ín 1969', '1969. Calle Cerd├ín. Al fondo, la entrada principal del Mercado Central.', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65481300, -0.88414100, '0101000020E610000003B00111E24AECBF71FF91E9D0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14951269296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14951269296.webp', 'https://www.flickr.com/photos/zaragozaantigua/14951269296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25381, 'Mercado Central 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Febrero 1966. Entrada al Mercado Central desde la Avenida C├®sar Augusto-calle Torre Nueva.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65560200, -0.88333000, '0101000020E6100000F86BB2463D44ECBF9A982EC4EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097137153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097137153.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097137153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25382, 'Pl. de Lanuza 1966', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 02/07/1966. "Plaza de Lanuza." En la imagen, fachada a la plaza de la manzana entre las calles Cerd├ín y Escuelas P├¡as.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65562300, -0.88343900, '0101000020E6100000A759A0DD2145ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15163516407.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15163516407.webp', 'https://www.flickr.com/photos/zaragozaantigua/15163516407/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25386, 'Calle Escuelas P├¡as 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Julio 1966. Calle Escuelas P├¡as. Al fondo, la iglesia de los Escolapios.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65529400, -0.88399900, '0101000020E6100000664B5645B849ECBFECA17DACE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15526419320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15526419320.webp', 'https://www.flickr.com/photos/zaragozaantigua/15526419320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25388, '4 Alcaldes 4, 1963', 'Camino de los "25 a├▒os de Paz" (sic), imagen de 4 de los 5 ├║ltimos alcaldes de la ciudad y del "Movimiento" (sic), capturada en 1963 durante la inauguraci├│n de la sucursal del Mercado Central de la Caja de Ahorros de Zaragoza y etc. De izquierda a derecha: Jos├® Mar├¡a Garc├¡a-Belenguer Garc├¡a (alcalde entre 1949-1954), Luis G├│mez Laguna (desde 1954), Juan Jos├® Rivas Bosch (entre 1939-1941), y Jos├® Mar├¡a S├ínchez Ventura (entre 1946-1949). Faltaba Francisco Caballero Ib├í├▒ez (entre 1941-1946), fallecido en 1954. Por arriba despunta el retrato del General├¡simo (sic). Fuente: "El municipio en Arag├│n", DPZ, 2004', 1963, 1963, 1963, 'Anos 60', 'CASCO HIST├ôRICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16420195809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16420195809.webp', 'https://www.flickr.com/photos/zaragozaantigua/16420195809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25389, 'Calle del Mercado 1877', '"Desde el Palacio de la Audiencia y sus gigantones del Coso, y por la calle Albarder├¡a, llamada hace poco Cerd├ín, llego al Mercado, una ancha calle que llaman plaza, y que se queda peque├▒a cuando los lugare├▒os la convierten en el zoco. Aqu├¡ cerca queda el Azoque que conduce a la vieja Morer├¡a, porque en Zaragoza todo est├í conectado, aunque no lo parezca. Subo a una casa de alquiler desde la que tengo buena vista, e instalo la c├ímara. Compruebo la luz, y hago varias capturas, seg├║n el sol. Hay justo abajo una fuente puesta por el Ayuntamiento, que me dicen que es muy reciente, aunque el agua no sale muy buena. Justo ah├¡ estaba la picota donde ajusticiaban a malhechores, y cortaron la cabeza al que llamaban Justicia. Esta fue plaza tambi├®n de toreros antes que la plaza del Campo del Toro, de justas y gestas de caballeros, de fuegos y hogueras, de capelardentes... Los contrastes de luz son brutales: de la oscuridad se pasa al deslumbre en un instante... ┬ícuidado! Con los toldos desplegados, la plaza parece encogerse, aunque no deja de entrar gente en ella. El bullicio es indescriptible. Si esta gente habla as├¡ del natural, c├│mo ser├í cuando se echen a gritar... A la izquierda est├í la calle de San Blas. A la derecha, la de la Torre Nueva. Al fondo, la de Antonio P├®rez, que termina en la puerta de San Ildefonso y que conserva un torre├│n de la Sudda musulmana. Ahora que el sol ya no cae como a plomo, nos vamos a comer a una antigua posada, en la calle de San Pablo." Del ap├│crifo "Diario de un Gabacho en Zaragoza" (Jean Laurent, 1878) Fuente visual: Fototeca del Patrimonio Hist├│rico (www.mcu.es) Archivo Ruiz Vernacci. Jean Laurent y C├¡a. Original composici├│n realizada a partir del positivado estereosc├│pico, por cortes├¡a del taller de GAZA.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65562300, -0.88343900, '0101000020E6100000A759A0DD2145ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17715945103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17715945103.webp', 'https://www.flickr.com/photos/zaragozaantigua/17715945103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25393, 'Plaza del Mercado 1591', 'Ilustraci├│n del art├¡culo "El suplicio de Lanuza", en la secci├│n "Momentos Hist├│ricos", de la revista "La Esfera" (1923), en que se recrean de aquellas formas los acontecimientos de Zaragoza de diciembre de 1591, que culminaron con la ejecuci├│n del Justiciazgo Juan de Lanuza, separando la cabeza de su tronco. El dibujo est├í localizado en la "plaza del Ahorcado", en realidad plaza del Mercado, donde estaba ubicada desde antiguo la "picota" o sitial de las ejecuciones p├║blicas. La dram├ítica altura de la picota de esta reproducci├│n, produce v├®rtigo. A la derecha, interpretaci├│n de la puerta de Toledo, del torre├│n de la Zuda, y de la puerta de la Triper├¡a. Fuente visual: dibujo de Ricardo Mar├¡n Llovet, revista "La Esfera" (Madrid)', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65580100, -0.88323900, '0101000020E6100000E3A7716F7E43ECBF90D78349F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22591062637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22591062637.webp', 'https://www.flickr.com/photos/zaragozaantigua/22591062637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25395, 'Calle Escuelas P├¡as 1968', 'Calle de las Escuelas P├¡as. Al fondo, la iglesia de los Escolapios. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65536500, -0.88406700, '0101000020E610000071218FE0464AECBFB6F81400E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22849889700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22849889700.webp', 'https://www.flickr.com/photos/zaragozaantigua/22849889700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
